export const simpleCounter = {
  name: 'Simple Counter',
  description: 'A basic counter with increment/decrement buttons',
  code: `// Simple Counter Example
const getColors = () => ({
  textDark: (window.globalVariables?.global_style_1) || '#333',
  success: (window.globalVariables?.global_style_6) || '#4CAF50',
  error: (window.globalVariables?.global_style_9) || '#f44336',
  textWhite: (window.globalVariables?.global_style_13) || 'white',
});
const colors = getColors();
let count = 0;
const container = document.createElement('div');
container.innerHTML = \`
    <div style="text-align: center; padding: 10px; font-family: Arial;">
        <h3 style="margin: 0 0 10px 0; color: \${colors.textDark};">Counter: <span id="count">0</span></h3>
        <button id="increment" style="margin: 0 5px; padding: 5px 10px; background: \${colors.success}; color: \${colors.textWhite}; border: none; border-radius: 3px; cursor: pointer;">+</button>
        <button id="decrement" style="margin: 0 5px; padding: 5px 10px; background: \${colors.error}; color: \${colors.textWhite}; border: none; border-radius: 3px; cursor: pointer;">-</button>
    </div>
\`;

document.body.appendChild(container);

document.getElementById('increment').onclick = () => {
    count++;
    document.getElementById('count').textContent = count;
    console.log('Count incremented to:', count);
};

document.getElementById('decrement').onclick = () => {
    count--;
    document.getElementById('count').textContent = count;
    console.log('Count decremented to:', count);
};`
};
